import React from "react";
import InfoPageLayout from "./InfoPageLayout";

const pageData = {
  title: "Contact Us",
  subtitle: "Get in touch with our team. We're here to help with sales, support, and general inquiries.",
  sections: [
    {
      title: "Contact Information",
      description: "Reach out to us through any of these channels.",
      gridClass: "info-grid-3",
      grid: [
        {
          title: "Sales",
          description: "Questions about our product or pricing?",
          list: ["sales@cybervault.io", "1-800-CYBER-VAULT", "Response within 24 hours"]
        },
        {
          title: "Support",
          description: "Technical help for existing customers.",
          list: ["support@cybervault.io", "24/7 Priority Support", "Average response: 2 hours"]
        },
        {
          title: "General",
          description: "Media, partnerships, or other inquiries.",
          list: ["info@cybervault.io", "press@cybervault.io", "Response within 48 hours"]
        }
      ]
    },
    {
      title: "Global Offices",
      description: "Visit us at one of our global locations.",
      bgColor: "#f8fafc",
      gridClass: "info-grid-3",
      grid: [
        {
          title: "San Francisco (HQ)",
          description: "1 CyberVault Way, Suite 400\nSan Francisco, CA 94105\nUnited States"
        },
        {
          title: "New York",
          description: "350 Fifth Avenue, Suite 5100\nNew York, NY 10118\nUnited States"
        },
        {
          title: "London",
          description: "25 Canada Square\nCanary Wharf, London E14 5LQ\nUnited Kingdom"
        }
      ]
    },
    {
      title: "Send Us a Message",
      description: "Fill out the form and we'll get back to you within 24 hours.",
      content: `
        <form class="contact-form">
          <div class="form-row">
            <div class="form-group">
              <label>Name</label>
              <input type="text" placeholder="Your name" />
            </div>
            <div class="form-group">
              <label>Email</label>
              <input type="email" placeholder="your@email.com" />
            </div>
          </div>
          <div class="form-group">
            <label>Subject</label>
            <select>
              <option>Sales Inquiry</option>
              <option>Technical Support</option>
              <option>Partnership</option>
              <option>Other</option>
            </select>
          </div>
          <div class="form-group">
            <label>Message</label>
            <textarea placeholder="How can we help?" rows="5"></textarea>
          </div>
          <button type="submit" class="btn btn-primary">Send Message</button>
        </form>
      `
    }
  ],
  color: "#0ea5e9"
};

function Contact() {
  return <InfoPageLayout {...pageData} />;
}

export default Contact;
